INSERT INTO sms_lessons (course_id, title, type, points, order_index, content) SELECT id, 'Comprendre la collecte de données terrain', 'notebook', 10, 1, '{"cells": [{"type": "md", "content": "## Pourquoi ce projet ?\n\nVous êtes recruté(e) comme agent MEAL pour une ONG qui intervient dans la région maritime du **Togo**. Une alerte nutritionnelle vient de tomber : il faut mesurer la malnutrition des enfants de 6 à 59 mois dans 5 districts de Lomé. Vous avez 10 jours et 8 enquêteurs.\n\nÀ la fin de ce projet, vous saurez **construire de A à Z** votre propre système de collecte KoboCollect, déployer l''enquête sur le terrain, et analyser les résultats — sans aucune connaissance préalable."}, {"type": "callout", "variant": "real", "title": "Situation réelle", "content": "Avant KoboCollect, les enquêtes se faisaient sur papier : 200 questionnaires, 3 semaines de saisie manuelle, des erreurs partout. Aujourd''hui, un enquêteur avec un téléphone Android collecte, géolocalise et envoie les données en temps réel. C''est ce que vous allez maîtriser."}, {"type": "md", "content": "### Les 3 grandes étapes de toute collecte\n\n1. **Concevoir** le formulaire (les questions à poser)\n2. **Collecter** sur le terrain avec l''app KoboCollect (Android)\n3. **Analyser** les données récupérées\n\nKoboToolbox est **gratuit et open-source**, utilisé par l''ONU, MSF, l''UNICEF et des milliers d''ONG en Afrique de l''Ouest."}, {"type": "resource", "title": "Créer un compte KoboToolbox gratuit", "url": "https://www.kobotoolbox.org/", "provider": "KoboToolbox", "desc": "Le serveur humanitaire est 100% gratuit pour les organisations à but non lucratif. Créez votre compte sur kf.kobotoolbox.org."}, {"type": "quiz", "question": "Quelle est la toute première étape d''une collecte de données ?", "opts": ["Acheter des téléphones", "Concevoir le formulaire (les questions)", "Recruter les enquêteurs", "Analyser les données"], "ans": 1}]}'::jsonb FROM sms_courses WHERE code = 'MEAL-01';
INSERT INTO sms_lessons (course_id, title, type, points, order_index, content) SELECT id, 'Concevoir un formulaire XLSForm — les bases', 'notebook', 15, 2, '{"cells": [{"type": "md", "content": "## Le format XLSForm\n\nUn formulaire KoboCollect se construit dans un simple tableur Excel appelé **XLSForm**. Trois onglets suffisent :\n\n- **survey** : la liste de vos questions\n- **choices** : les options des questions à choix\n- **settings** : le titre et l''identifiant du formulaire"}, {"type": "md", "content": "### L''onglet `survey` — 3 colonnes essentielles\n\n| Colonne | Rôle | Exemple |\n|---|---|---|\n| `type` | le type de question | `text`, `integer`, `decimal`, `select_one`, `geopoint` |\n| `name` | nom interne (sans espace) | `child_name`, `age_months` |\n| `label` | la question affichée | « Nom de l''enfant »|"}, {"type": "callout", "variant": "tip", "title": "Astuce de pro", "content": "Le `name` ne doit JAMAIS contenir d''espace ni d''accent (utilisez `age_months`, pas « âge mois »). C''est le nom technique qu''on retrouvera dans les données. Le `label`, lui, est ce que voit l''enquêteur — il peut tout contenir."}, {"type": "code", "lang": "python", "code": "# Représentons notre premier formulaire en Python pour bien comprendre\nsurvey = [\n    {\"type\": \"text\",     \"name\": \"enqueteur\",  \"label\": \"Nom de l''enqueteur\"},\n    {\"type\": \"text\",     \"name\": \"child_name\", \"label\": \"Nom de l''enfant\"},\n    {\"type\": \"integer\",  \"name\": \"age_months\", \"label\": \"Age en mois\"},\n    {\"type\": \"select_one sexe\", \"name\": \"sexe\", \"label\": \"Sexe de l''enfant\"},\n]\nfor q in survey:\n    print(f\"[{q[''type'']:>18}] {q[''label'']}\")\n", "output": "[              text] Nom de l''enqueteur\n[              text] Nom de l''enfant\n[           integer] Age en mois\n[ select_one sexe] Sexe de l''enfant"}, {"type": "md", "content": "### L''onglet `choices` — pour les questions à choix\n\nQuand vous écrivez `select_one sexe`, KoboCollect va chercher la liste `sexe` dans l''onglet `choices` :\n\n| list_name | name | label |\n|---|---|---|\n| sexe | M | Masculin |\n| sexe | F | Féminin |"}, {"type": "quiz", "question": "Vous voulez une question « Quel est le district ? » avec 5 districts possibles. Quel type utilisez-vous ?", "opts": ["text", "integer", "select_one district", "geopoint"], "ans": 2}]}'::jsonb FROM sms_courses WHERE code = 'MEAL-01';
INSERT INTO sms_lessons (course_id, title, type, points, order_index, content) SELECT id, 'Validation, logique conditionnelle et GPS', 'notebook', 15, 3, '{"cells": [{"type": "md", "content": "## Rendre le formulaire intelligent\n\nUn bon formulaire **empêche les erreurs** dès la saisie. Trois outils puissants : les contraintes, l''affichage conditionnel, et la géolocalisation."}, {"type": "md", "content": "### 1. `constraint` — interdire les valeurs absurdes\n\nUn enfant de l''enquête a entre 6 et 59 mois. On l''écrit avec un point `.` qui représente « la réponse à cette question » :\n\n```\ntype: integer | name: age_months | constraint: . >= 6 and . <= 59\n```\n\nSi l''enquêteur tape 200, KoboCollect refuse et affiche votre `constraint_message`."}, {"type": "callout", "variant": "warning", "title": "Erreur fréquente des débutants", "content": "On écrit `. >= 6` et NON `age_months >= 6`. Le point représente la valeur de la question courante. Pour référencer une AUTRE question, on utilise ${autre_question}."}, {"type": "md", "content": "### 2. `relevant` — afficher une question selon une réponse précédente\n\nNe poser la question « Nombre de grossesses » que si `sexe = F` :\n\n```\ntype: integer | name: nb_grossesses | relevant: ${sexe} = ''F''\n```"}, {"type": "md", "content": "### 3. `geopoint` — capturer la position GPS\n\nLe type `geopoint` capture latitude + longitude + altitude. Indispensable pour cartographier ensuite les bénéficiaires (vous le ferez au Projet 2 avec QGIS)."}, {"type": "code", "lang": "python", "code": "# Formulaire enrichi avec validation, logique et GPS\nsurvey = [\n    {\"type\": \"integer\", \"name\": \"age_months\", \"label\": \"Age (mois)\",\n     \"constraint\": \". >= 6 and . <= 59\",\n     \"constraint_message\": \"L''age doit etre entre 6 et 59 mois\"},\n    {\"type\": \"select_one sexe\", \"name\": \"sexe\", \"label\": \"Sexe\"},\n    {\"type\": \"integer\", \"name\": \"nb_grossesses\", \"label\": \"Nombre de grossesses\",\n     \"relevant\": \"${sexe} = ''F''\"},\n    {\"type\": \"decimal\", \"name\": \"muac_mm\", \"label\": \"MUAC (mm)\",\n     \"constraint\": \". > 50 and . < 300\"},\n    {\"type\": \"geopoint\", \"name\": \"gps\", \"label\": \"Position GPS du menage\"},\n]\nprint(f\"Formulaire pret : {len(survey)} questions, avec validation + GPS\")\n", "output": "Formulaire pret : 5 questions, avec validation + GPS"}, {"type": "resource", "title": "Référence officielle XLSForm", "url": "https://xlsform.org/", "provider": "Open Source", "desc": "La documentation de référence du format XLSForm, maintenue par la communauté ODK. Tous les types de questions et fonctions y sont listés."}, {"type": "quiz", "question": "Comment n''afficher une question QUE si la personne a répondu « Oui » (valeur ''oui'') à la question consentement ?", "opts": ["constraint: consentement = oui", "relevant: ${consentement} = ''oui''", "required: oui", "appearance: oui"], "ans": 1}]}'::jsonb FROM sms_courses WHERE code = 'MEAL-01';
INSERT INTO sms_lessons (course_id, title, type, points, order_index, content) SELECT id, 'Notebook live — simuler et nettoyer les données', 'notebook', 20, 4, '{"cells": [{"type": "md", "content": "## De la collecte à la donnée exploitable\n\nVos 8 enquêteurs ont collecté 200 fiches. KoboToolbox vous renvoie un fichier de données. Avant toute analyse, il faut **nettoyer** : valeurs manquantes, doublons, valeurs aberrantes.\n\nCi-dessous, un **vrai notebook Python que vous pouvez exécuter et modifier directement ici** (il tourne dans votre navigateur, gratuitement)."}, {"type": "embed", "title": "Notebook live : simuler les données de l''enquête", "code": "import random\nrandom.seed(42)\ndistricts = [''Agoe'',''Golfe'',''Zio'',''Bas-Mono'',''Lacs'']\ndata = []\nfor i in range(1, 201):\n    muac = round(random.gauss(130, 18), 1)\n    data.append({''id'': f''TG-{i:03d}'', ''district'': random.choice(districts),\n                 ''age'': random.randint(6,59), ''muac_mm'': max(60, min(200, muac))})\nprint(f\"{len(data)} enfants simules\")\nprint(\"3 premiers :\", data[:3])"}, {"type": "callout", "variant": "real", "title": "Ce que vous voyez ci-dessus", "content": "C''est un notebook Jupyter complet qui tourne 100% dans votre navigateur (technologie JupyterLite/WebAssembly). Cliquez dans la cellule, modifiez le code, appuyez sur Shift+Entrée pour l''exécuter. Aucune installation, aucun compte, aucun coût."}, {"type": "md", "content": "### Nettoyage : les 3 réflexes systématiques\n\n1. **Valeurs manquantes** → `df.dropna()` ou remplir\n2. **Doublons** → `df.drop_duplicates()`\n3. **Valeurs aberrantes** → filtrer (un MUAC de 5 mm est impossible)"}, {"type": "embed", "title": "Notebook live : nettoyer avec pandas", "code": "import pandas as pd\nimport numpy as np\nnp.random.seed(1)\ndf = pd.DataFrame({\n  ''muac_mm'': np.append(np.random.normal(130,18,18), [np.nan, 5]),\n})\nprint(\"Avant :\", len(df), \"lignes\")\ndf = df.dropna()                      # enleve les manquants\ndf = df[(df.muac_mm > 50) & (df.muac_mm < 300)]  # enleve les aberrants\nprint(\"Apres nettoyage :\", len(df), \"lignes\")\nprint(\"MUAC moyen :\", round(df.muac_mm.mean(),1), \"mm\")"}, {"type": "resource", "title": "Ouvrir un Colab vierge (sauvegarde sur Google Drive)", "url": "https://colab.research.google.com/", "provider": "Google Colab", "desc": "Pour des analyses plus lourdes et sauvegarder votre travail, Google Colab est gratuit (un compte Google suffit). Idéal pour vos vrais projets."}]}'::jsonb FROM sms_courses WHERE code = 'MEAL-01';
INSERT INTO sms_lessons (course_id, title, type, points, order_index, content) SELECT id, 'Analyser les indicateurs nutritionnels (MEAL)', 'notebook', 20, 5, '{"cells": [{"type": "md", "content": "## Transformer les données en décisions\n\nLe but du MEAL n''est pas de produire des chiffres, mais d''**éclairer une décision**. Ici : faut-il déclencher une réponse nutritionnelle d''urgence ?"}, {"type": "md", "content": "### Les seuils OMS / SPHERE (à connaître par cœur)\n\n| MUAC | Statut | Action |\n|---|---|---|\n| < 115 mm | **MAS** (sévère) | Référer en urgence |\n| 115–125 mm | **MAM** (modérée) | Supplémentation |\n| ≥ 125 mm | Normal | Surveillance |\n\nSi la prévalence **MAG** (MAS+MAM) dépasse **15%**, c''est une situation d''urgence selon les standards SPHERE."}, {"type": "embed", "title": "Notebook live : classifier et calculer la prévalence", "code": "import pandas as pd, numpy as np\nnp.random.seed(42)\ndf = pd.DataFrame({''muac_mm'': np.random.normal(130,18,200).clip(60,200)})\n\ndef classer(m):\n    if m < 115: return ''MAS''\n    elif m < 125: return ''MAM''\n    return ''Normal''\n\ndf[''statut''] = df[''muac_mm''].apply(classer)\nprev = (df[''statut''].value_counts() / len(df) * 100).round(1)\nprint(prev.to_string())\nmag = prev.get(''MAS'',0) + prev.get(''MAM'',0)\nprint(f\"\\nPrevalence MAG : {mag:.1f}%\")\nprint(\"ALERTE URGENCE\" if mag > 15 else \"Situation maitrisee\")"}, {"type": "callout", "variant": "tip", "title": "Le réflexe MEAL", "content": "Toujours comparer votre indicateur à un SEUIL de référence (SPHERE, OMS, cadre logique du projet). Un chiffre seul ne dit rien ; un chiffre comparé à un seuil déclenche une action."}, {"type": "quiz", "question": "Votre enquête donne 8% MAS + 18% MAM. Quelle est la prévalence MAG et que décidez-vous ?", "opts": ["10%, situation normale", "26%, alerte urgence (> seuil 15%)", "8%, surveillance", "18%, pas d''action"], "ans": 1}]}'::jsonb FROM sms_courses WHERE code = 'MEAL-01';
INSERT INTO sms_lessons (course_id, title, type, points, order_index, content) SELECT id, 'Capstone — déployer VOTRE formulaire complet', 'notebook', 20, 6, '{"cells": [{"type": "md", "content": "## Projet final : vous êtes autonome\n\nVous maîtrisez maintenant tout le cycle. Pour valider ce projet, voici le **formulaire nutritionnel complet** que vous savez désormais construire entièrement vous-même."}, {"type": "embed", "title": "Notebook live : générer le XLSForm complet + tableau de bord", "code": "import pandas as pd\nsurvey = pd.DataFrame([\n  {''type'':''start'',''name'':''start'',''label'':''''},\n  {''type'':''text'',''name'':''enqueteur'',''label'':\"Enqueteur\"},\n  {''type'':''select_one district'',''name'':''district'',''label'':''District''},\n  {''type'':''text'',''name'':''child_name'',''label'':\"Nom enfant\"},\n  {''type'':''integer'',''name'':''age_months'',''label'':''Age (mois)'',''constraint'':''. >= 6 and . <= 59''},\n  {''type'':''select_one sexe'',''name'':''sexe'',''label'':''Sexe''},\n  {''type'':''decimal'',''name'':''muac_mm'',''label'':''MUAC (mm)'',''constraint'':''. > 50 and . < 300''},\n  {''type'':''geopoint'',''name'':''gps'',''label'':''GPS menage''},\n])\nprint(\"=== VOTRE FORMULAIRE KOBOCOLLECT ===\")\nprint(survey[[''type'',''name'',''label'']].to_string(index=False))\nprint(f\"\\n{len(survey)} questions, pret a deployer sur kf.kobotoolbox.org\")"}, {"type": "md", "content": "### Comment déployer pour de vrai (3 étapes)\n\n1. Recopiez ce formulaire dans un Excel (onglets survey/choices/settings)\n2. Sur **kf.kobotoolbox.org** : *Nouveau projet → Importer un XLSForm*\n3. *Deploy* → installez l''app **KoboCollect** sur Android, connectez le serveur, collectez !"}, {"type": "resource", "title": "Télécharger l''app KoboCollect (Android, gratuit)", "url": "https://play.google.com/store/apps/details?id=org.koboc.collect.android", "provider": "Google Play", "desc": "L''application mobile officielle pour la collecte hors-ligne sur le terrain. Synchronise dès qu''une connexion est disponible."}, {"type": "resource", "title": "pykobo — récupérer vos données par API en Python", "url": "https://github.com/pvernier/pykobo", "provider": "GitHub (open source)", "desc": "Module Python gratuit qui télécharge automatiquement les soumissions Kobo dans un DataFrame pandas. Vous l''utiliserez dans vos vrais projets."}, {"type": "callout", "variant": "real", "title": "Félicitations", "content": "Vous savez maintenant concevoir, valider, déployer et analyser n''importe quelle enquête KoboCollect. C''est exactement la compétence demandée dans les offres d''emploi MEAL en Afrique de l''Ouest. Au Projet 2, vous cartographierez ces données GPS avec QGIS."}]}'::jsonb FROM sms_courses WHERE code = 'MEAL-01';
INSERT INTO sms_lessons (course_id, title, type, points, order_index, content) SELECT id, 'Le terrain en cartes : comprendre le SIG', 'notebook', 10, 1, '{"cells": [{"type": "md", "content": "## Nouvelle mission\n\nVotre ONG gère 58 coopératives maraîchères dans la région de **Kara (Togo)**. Le bailleur (FIDA) demande : *« Où sont exactement les bénéficiaires ? Quels villages ne sont pas couverts par un point d''eau à moins de 2 km ? »*\n\nRéponse : un **SIG** (Système d''Information Géographique). Vous allez apprendre QGIS, le SIG open-source de référence."}, {"type": "callout", "variant": "real", "title": "Pourquoi c''est crucial", "content": "Les données KoboCollect du Projet 1 contiennent des coordonnées GPS. Sans cartographie, ce ne sont que des chiffres. Avec QGIS, elles deviennent des cartes qui montrent où agir — et qui convainquent les bailleurs."}, {"type": "md", "content": "### Vocabulaire de base\n\n- **Couche (layer)** : un jeu de données géographiques (les points d''eau, les villages, les routes...)\n- **Vecteur** : points, lignes, polygones (≠ raster = image satellite)\n- **Attributs** : le tableau derrière chaque objet (nom du village, population...)\n- **Projection (CRS)** : comment on aplatit la Terre ronde sur une carte plate"}, {"type": "resource", "title": "Télécharger QGIS (gratuit, Windows/Mac/Linux)", "url": "https://qgis.org/fr/site/forusers/download.html", "provider": "QGIS (open source)", "desc": "QGIS est 100% gratuit et open-source. Téléchargez la version LTR (Long Term Release) pour la stabilité."}, {"type": "quiz", "question": "Vos données GPS de l''enquête Kobo sont des points. Dans QGIS, c''est une couche de type :", "opts": ["raster", "vecteur (points)", "tableur", "image"], "ans": 1}]}'::jsonb FROM sms_courses WHERE code = 'MEAL-02';
INSERT INTO sms_lessons (course_id, title, type, points, order_index, content) SELECT id, 'Coordonnées et projections (sans maths)', 'notebook', 15, 2, '{"cells": [{"type": "md", "content": "## Le piège n°1 des débutants : les projections\n\nLa Terre est ronde, une carte est plate. Pour passer de l''une à l''autre, on utilise un **système de coordonnées (CRS)**. Se tromper de CRS = des points qui atterrissent dans l''océan."}, {"type": "md", "content": "### Les 2 CRS que vous utiliserez en Afrique de l''Ouest\n\n| CRS | Code | Quand l''utiliser |\n|---|---|---|\n| WGS 84 | **EPSG:4326** | GPS, KoboCollect (degrés lat/lon) |\n| UTM 31N | **EPSG:32631** | Mesurer des distances en mètres (Togo, Bénin) |"}, {"type": "callout", "variant": "warning", "title": "Règle d''or", "content": "Vos données GPS arrivent toujours en EPSG:4326 (degrés). Pour CALCULER des distances ou des surfaces en mètres, reprojetez en UTM (EPSG:32631 pour le Togo). Sinon vos « 2 km » seront faux."}, {"type": "embed", "title": "Notebook live : comprendre une coordonnée GPS", "code": "# Une coordonnee = (longitude, latitude) en degres decimaux\npoints_eau = [\n  (\"Forage Kara-centre\", 1.186, 9.551),\n  (\"Puits Pya\",          1.215, 9.605),\n  (\"Forage Lama\",        1.094, 9.495),\n]\nfor nom, lon, lat in points_eau:\n    print(f\"{nom:22} lon={lon}  lat={lat}\")\nprint(\"\\nCes points viennent directement du champ ''geopoint'' de KoboCollect\")"}, {"type": "quiz", "question": "Vous voulez savoir si un village est à moins de 2 km d''un forage. Dans quel CRS devez-vous travailler ?", "opts": ["EPSG:4326 (degrés)", "EPSG:32631 (UTM, mètres)", "Peu importe", "Aucun"], "ans": 1}]}'::jsonb FROM sms_courses WHERE code = 'MEAL-02';
INSERT INTO sms_lessons (course_id, title, type, points, order_index, content) SELECT id, 'Importer les données GPS de KoboCollect', 'notebook', 15, 3, '{"cells": [{"type": "md", "content": "## Du formulaire Kobo à la carte\n\nLes données collectées au Projet 1 contiennent une colonne GPS. On va les transformer en couche cartographique. Deux formats que QGIS adore :\n\n- **CSV** avec colonnes `latitude` / `longitude`\n- **GeoJSON** (le standard web ouvert)"}, {"type": "embed", "title": "Notebook live : convertir un CSV Kobo en GeoJSON", "code": "import json\n# Donnees telechargees depuis KoboToolbox\nmenages = [\n  {\"id\":\"TG-001\",\"village\":\"Pya\",\"lat\":9.605,\"lon\":1.215,\"muac\":118},\n  {\"id\":\"TG-002\",\"village\":\"Lama\",\"lat\":9.495,\"lon\":1.094,\"muac\":131},\n  {\"id\":\"TG-003\",\"village\":\"Kara\",\"lat\":9.551,\"lon\":1.186,\"muac\":109},\n]\ngeojson = {\"type\":\"FeatureCollection\",\"features\":[]}\nfor m in menages:\n    geojson[\"features\"].append({\n      \"type\":\"Feature\",\n      \"geometry\":{\"type\":\"Point\",\"coordinates\":[m[\"lon\"], m[\"lat\"]]},\n      \"properties\":{\"id\":m[\"id\"], \"village\":m[\"village\"], \"muac\":m[\"muac\"]}\n    })\nprint(json.dumps(geojson, indent=2)[:300], \"...\")\nprint(f\"\\n{len(geojson[''features''])} points prets a ouvrir dans QGIS\")"}, {"type": "md", "content": "### Dans QGIS (manuellement)\n\n1. *Couche → Ajouter une couche → Ajouter une couche de texte délimité (CSV)*\n2. Indiquez les colonnes X = longitude, Y = latitude, CRS = EPSG:4326\n3. Vos ménages apparaissent sur la carte !"}, {"type": "callout", "variant": "tip", "title": "Astuce GeoPackage", "content": "Préférez le format `.gpkg` (GeoPackage) au vieux Shapefile : un seul fichier, pas de limite de nom de colonne, open-source. C''est le format moderne recommandé par QGIS."}, {"type": "resource", "title": "Données frontières administratives du Togo (gratuites)", "url": "https://data.humdata.org/", "provider": "HDX (OCHA)", "desc": "Le Humanitarian Data Exchange fournit gratuitement les limites administratives (régions, préfectures) de tous les pays — indispensable pour vos fonds de carte."}]}'::jsonb FROM sms_courses WHERE code = 'MEAL-02';
INSERT INTO sms_lessons (course_id, title, type, points, order_index, content) SELECT id, 'Analyse spatiale — répondre à la question du bailleur', 'notebook', 20, 4, '{"cells": [{"type": "md", "content": "## La vraie question : couverture en eau\n\n*« Quels villages n''ont pas de point d''eau à moins de 2 km ? »* C''est une **analyse de proximité** (buffer + jointure spatiale)."}, {"type": "md", "content": "### Les 3 outils d''analyse que vous utiliserez sans cesse\n\n1. **Tampon (buffer)** : zone de 2 km autour de chaque forage\n2. **Jointure spatiale** : associer chaque village à la zone qui le contient\n3. **Sélection par localisation** : « tous les villages HORS des zones »"}, {"type": "embed", "title": "Notebook live : calculer les distances (logique du buffer)", "code": "import math\ndef distance_km(lat1, lon1, lat2, lon2):\n    # Formule de Haversine (distance reelle sur la Terre)\n    R = 6371\n    dlat = math.radians(lat2-lat1); dlon = math.radians(lon2-lon1)\n    a = math.sin(dlat/2)**2 + math.cos(math.radians(lat1))*math.cos(math.radians(lat2))*math.sin(dlon/2)**2\n    return round(R * 2 * math.asin(math.sqrt(a)), 2)\n\nforage = (9.551, 1.186)  # Kara-centre\nvillages = {\"Pya\":(9.605,1.215), \"Lama\":(9.495,1.094), \"Atalote\":(9.700,1.300)}\nfor v,(lat,lon) in villages.items():\n    d = distance_km(*forage, lat, lon)\n    statut = \"COUVERT\" if d <= 2 else \"NON COUVERT (a equiper)\"\n    print(f\"{v:10} {d} km -> {statut}\")"}, {"type": "callout", "variant": "real", "title": "Décision terrain", "content": "Cette analyse a permis à une ONG au nord-Togo d''identifier 7 villages sans accès à l''eau dans un rayon de 2 km. Résultat : 7 nouveaux forages programmés dans le plan d''action. Voilà du MEAL qui change des vies."}, {"type": "quiz", "question": "Pour créer une zone de 2 km autour de chaque forage, quel outil QGIS utilisez-vous ?", "opts": ["Jointure d''attributs", "Tampon (buffer)", "Calculatrice de champ", "Géocodage"], "ans": 1}]}'::jsonb FROM sms_courses WHERE code = 'MEAL-02';
INSERT INTO sms_lessons (course_id, title, type, points, order_index, content) SELECT id, 'Produire des cartes professionnelles', 'notebook', 20, 5, '{"cells": [{"type": "md", "content": "## La carte qui convainc le bailleur\n\nUne analyse invisible ne sert à rien. QGIS a un **Composeur d''impression** (mise en page) pour produire des cartes A4/A3 avec titre, légende, échelle, flèche du nord et logo."}, {"type": "md", "content": "### La checklist d''une carte pro (les 6 éléments obligatoires)\n\n1. **Titre** clair\n2. **Légende** lisible\n3. **Échelle** (barre + ratio)\n4. **Flèche du nord**\n5. **Source des données** et date\n6. **Logo** de l''organisation"}, {"type": "md", "content": "### Symbologie : faire parler les couleurs\n\nColorez les villages par statut nutritionnel : rouge = MAS élevé, vert = normal. C''est la *symbologie graduée* — un dégradé qui rend la carte immédiatement compréhensible."}, {"type": "embed", "title": "Notebook live : préparer la classification couleur", "code": "villages = [\n  {\"nom\":\"Pya\",\"mag_pct\":28}, {\"nom\":\"Lama\",\"mag_pct\":12},\n  {\"nom\":\"Kara\",\"mag_pct\":38}, {\"nom\":\"Atalote\",\"mag_pct\":9},\n]\ndef couleur(p):\n    if p >= 25: return \"ROUGE (urgence)\"\n    elif p >= 15: return \"ORANGE (alerte)\"\n    return \"VERT (ok)\"\nfor v in sorted(villages, key=lambda x:-x[''mag_pct'']):\n    print(f\"{v[''nom'']:10} MAG {v[''mag_pct'']:>2}%  ->  {couleur(v[''mag_pct''])}\")"}, {"type": "resource", "title": "Manuel de formation QGIS officiel (gratuit, FR)", "url": "https://docs.qgis.org/latest/fr/docs/training_manual/", "provider": "QGIS (open source)", "desc": "Le manuel de formation complet de QGIS, traduit en français, couvre du débutant à l''expert. Une référence gratuite inestimable."}]}'::jsonb FROM sms_courses WHERE code = 'MEAL-02';
INSERT INTO sms_lessons (course_id, title, type, points, order_index, content) SELECT id, 'Automatiser avec PyQGIS', 'notebook', 20, 6, '{"cells": [{"type": "md", "content": "## Quand vous avez 50 cartes à faire\n\nFaire 58 cartes à la main = 2 jours. Avec **PyQGIS** (la console Python de QGIS) et l''**Atlas**, c''est 5 minutes. C''est le passage du débutant au professionnel autonome."}, {"type": "md", "content": "### La console Python de QGIS\n\nDans QGIS : *Extensions → Console Python*. Vous pilotez tout QGIS en code."}, {"type": "code", "lang": "python", "code": "# PyQGIS — charger une couche et compter les objets (a executer DANS QGIS)\nfrom qgis.core import QgsVectorLayer\n\nchemin = \"/data/menages_kara.gpkg\"\ncouche = QgsVectorLayer(chemin, \"Menages\", \"ogr\")\n\nif couche.isValid():\n    print(f\"Couche chargee : {couche.featureCount()} menages\")\n    # Filtrer les cas severes\n    couche.selectByExpression(''\"muac\" < 115'')\n    print(f\"Cas MAS selectionnes : {couche.selectedFeatureCount()}\")\nelse:\n    print(\"Erreur : couche invalide (verifier le chemin)\")\n", "output": "Couche chargee : 200 menages\nCas MAS selectionnes : 16"}, {"type": "callout", "variant": "tip", "title": "L''Atlas QGIS", "content": "L''Atlas génère automatiquement une carte par entité (une par district, par exemple). Configurez la mise en page une fois, l''Atlas produit les 5 cartes des 5 districts d''un coup, en PDF."}, {"type": "resource", "title": "PyQGIS Developer Cookbook (officiel, gratuit)", "url": "https://docs.qgis.org/latest/en/docs/pyqgis_developer_cookbook/", "provider": "QGIS (open source)", "desc": "Le livre de recettes officiel pour automatiser QGIS en Python : charger des couches, analyser, exporter des cartes en boucle."}]}'::jsonb FROM sms_courses WHERE code = 'MEAL-02';
INSERT INTO sms_lessons (course_id, title, type, points, order_index, content) SELECT id, 'Capstone — atlas de couverture WASH', 'notebook', 20, 7, '{"cells": [{"type": "md", "content": "## Projet final : votre atlas complet\n\nVous combinez tout : import des données Kobo, analyse de proximité, symbologie, et génération automatique d''un atlas de cartes par district. C''est livrable tel quel à un bailleur."}, {"type": "embed", "title": "Notebook live : synthèse de couverture par district", "code": "import pandas as pd\ndata = pd.DataFrame([\n  {\"district\":\"Agoe\",\"villages\":12,\"couverts\":9},\n  {\"district\":\"Golfe\",\"villages\":15,\"couverts\":15},\n  {\"district\":\"Zio\",\"villages\":10,\"couverts\":6},\n  {\"district\":\"Bas-Mono\",\"villages\":8,\"couverts\":3},\n  {\"district\":\"Lacs\",\"villages\":5,\"couverts\":5},\n])\ndata[\"taux_%\"] = (data.couverts/data.villages*100).round(0)\ndata[\"priorite\"] = data[\"taux_%\"].apply(lambda t:\"HAUTE\" if t<70 else \"ok\")\nprint(data.to_string(index=False))\nprint(f\"\\nVillages a equiper en priorite : {(data.villages-data.couverts).sum()}\")"}, {"type": "callout", "variant": "real", "title": "Vous êtes cartographe MEAL", "content": "Vous savez désormais transformer des coordonnées GPS brutes en cartes décisionnelles professionnelles. Combiné au Projet 1 (collecte), vous couvrez déjà 2/3 de la chaîne MEAL. Le Projet 3 va tout automatiser."}, {"type": "resource", "title": "Ouvrir QGIS dans le cloud (gratuit, sans installation)", "url": "https://qgiscloud.com/", "provider": "QGIS Cloud", "desc": "Pour partager vos cartes en ligne gratuitement, ou travailler sans installer QGIS sur un poste limité."}]}'::jsonb FROM sms_courses WHERE code = 'MEAL-02';
INSERT INTO sms_lessons (course_id, title, type, points, order_index, content) SELECT id, 'Penser comme un architecte MEAL', 'notebook', 10, 1, '{"cells": [{"type": "md", "content": "## La mission finale\n\nDirecteur pays satisfait, le bailleur (Banque Mondiale, programme FSRP) veut maintenant un **rapport trimestriel automatique** : dès que de nouvelles données Kobo arrivent, le système produit tableaux, cartes et PDF, sans intervention humaine.\n\nC''est le sommet du métier : le **pipeline MEAL automatisé**. Vous allez combiner KoboCollect (Projet 1) + Python + QGIS (Projet 2) en un seul flux."}, {"type": "md", "content": "### L''architecture d''un pipeline MEAL\n\n```\nKoboToolbox (API)  ->  Python (nettoyage + analyse)  ->  Cartes QGIS  ->  Rapport PDF/Excel\n```\n\nChaque maillon, vous le maîtrisez déjà. Il reste à les **assembler** et à **automatiser**."}, {"type": "callout", "variant": "real", "title": "Le niveau attendu", "content": "Un expert MEAL senior en Afrique de l''Ouest gagne sa place précisément parce qu''il sait automatiser ce que les autres font à la main pendant des semaines. C''est cette compétence qui se monnaie."}, {"type": "quiz", "question": "Dans un pipeline MEAL, quel est le bon ordre ?", "opts": ["PDF → analyse → collecte", "Collecte API → nettoyage/analyse → cartes → rapport", "Cartes → collecte → PDF", "Analyse → collecte → cartes"], "ans": 1}]}'::jsonb FROM sms_courses WHERE code = 'MEAL-03';
INSERT INTO sms_lessons (course_id, title, type, points, order_index, content) SELECT id, 'Connexion automatique à l''API KoboToolbox', 'notebook', 15, 2, '{"cells": [{"type": "md", "content": "## Récupérer les données sans clic\n\nFini le téléchargement manuel. L''**API KoboToolbox** permet à Python d''aller chercher les soumissions automatiquement. Il faut un **token** (votre clé personnelle, dans les paramètres de votre compte Kobo)."}, {"type": "code", "lang": "python", "code": "# Recuperer les donnees Kobo par API (requests)\nimport requests\n\nKOBO_URL = \"https://kf.kobotoolbox.org/api/v2\"\nTOKEN = \"VOTRE_TOKEN_ICI\"   # Compte Kobo > Parametres > Securite\nASSET = \"aXXXXXXXXXXXXX\"    # identifiant du formulaire\n\nheaders = {\"Authorization\": f\"Token {TOKEN}\"}\nurl = f\"{KOBO_URL}/assets/{ASSET}/data/?format=json\"\n# r = requests.get(url, headers=headers)   # decommente avec ton token\n# data = r.json()[\"results\"]\nprint(\"Pret a telecharger les soumissions automatiquement\")\nprint(\"Endpoint :\", url)\n", "output": "Pret a telecharger les soumissions automatiquement\nEndpoint : https://kf.kobotoolbox.org/api/v2/assets/aXXXXXXXXXXXXX/data/?format=json"}, {"type": "callout", "variant": "warning", "title": "Sécurité du token", "content": "Ne mettez JAMAIS votre token en clair dans un fichier partagé ou sur GitHub. Utilisez des variables d''environnement. Un token volé = accès à toutes vos données bénéficiaires."}, {"type": "resource", "title": "koboextractor — wrapper API officiel (PyPI, gratuit)", "url": "https://pypi.org/project/koboextractor/", "provider": "PyPI (open source)", "desc": "pip install koboextractor : télécharge et structure automatiquement les réponses Kobo. Documentation et exemples inclus."}, {"type": "resource", "title": "Documentation API KoboToolbox", "url": "https://support.kobotoolbox.org/api.html", "provider": "KoboToolbox", "desc": "Le guide officiel de l''API : authentification, récupération des données, déploiement de formulaires par programmation."}]}'::jsonb FROM sms_courses WHERE code = 'MEAL-03';
INSERT INTO sms_lessons (course_id, title, type, points, order_index, content) SELECT id, 'Notebook live — le moteur d''analyse', 'notebook', 20, 3, '{"cells": [{"type": "md", "content": "## Le cœur du pipeline\n\nUne fois les données récupérées, une seule fonction doit produire tous les indicateurs du cadre logique. On la teste ici en live."}, {"type": "embed", "title": "Notebook live : moteur d''indicateurs MEAL réutilisable", "code": "import pandas as pd, numpy as np\nnp.random.seed(7)\n# Simule des donnees multi-districts comme l''API les renverrait\ndf = pd.DataFrame({\n  ''district'': np.random.choice([''Agoe'',''Golfe'',''Zio'',''Bas-Mono'',''Lacs''],300),\n  ''muac_mm'': np.random.normal(128,17,300).clip(60,200),\n  ''sexe'': np.random.choice([''M'',''F''],300),\n})\ndef indicateurs(d):\n    d = d.copy()\n    d[''mag''] = d[''muac_mm''] < 125\n    return pd.Series({\n      ''n'': len(d),\n      ''MAG_%'': round(d[''mag''].mean()*100,1),\n      ''MUAC_moyen'': round(d[''muac_mm''].mean(),1),\n    })\n# Un seul appel produit le tableau par district !\nrapport = df.groupby(''district'').apply(indicateurs)\nprint(rapport.to_string())"}, {"type": "callout", "variant": "tip", "title": "Le principe DRY", "content": "« Don''t Repeat Yourself » : écrivez la fonction d''indicateurs UNE fois, appliquez-la à chaque district, chaque trimestre, chaque projet. C''est ce qui transforme 3 semaines de travail en 3 secondes."}, {"type": "md", "content": "### `groupby` : votre meilleur ami MEAL\n\nLa fonction `groupby` agrège par n''importe quelle dimension : district, sexe, tranche d''âge, période. C''est 80% de l''analyse MEAL en une ligne."}]}'::jsonb FROM sms_courses WHERE code = 'MEAL-03';
INSERT INTO sms_lessons (course_id, title, type, points, order_index, content) SELECT id, 'Générer le rapport Excel automatiquement', 'notebook', 15, 4, '{"cells": [{"type": "md", "content": "## Le livrable que tout le monde ouvre : Excel\n\n`openpyxl` permet à Python d''écrire des fichiers Excel formatés — onglets multiples, couleurs, formules. Le bailleur reçoit un classeur propre, généré automatiquement."}, {"type": "embed", "title": "Notebook live : exporter un classeur Excel structuré", "code": "import pandas as pd\nsynthese = pd.DataFrame([\n  {''Indicateur'':''Enfants enquetes'',''Valeur'':300,''Cible'':250,''Atteint'':''Oui''},\n  {''Indicateur'':''Prevalence MAG (%)'',''Valeur'':24.0,''Cible'':15.0,''Atteint'':''Non''},\n  {''Indicateur'':''Districts couverts'',''Valeur'':5,''Cible'':5,''Atteint'':''Oui''},\n])\nprint(synthese.to_string(index=False))\n# synthese.to_excel(''rapport_T1.xlsx'', index=False)  # genere le fichier\nprint(\"\\n-> rapport_T1.xlsx genere (3 indicateurs vs cibles du cadre logique)\")"}, {"type": "callout", "variant": "real", "title": "Comparer à la cible", "content": "Un rapport MEAL professionnel ne montre jamais une valeur seule : il la compare TOUJOURS à la cible du cadre logique. « 24% » ne dit rien ; « 24% contre une cible de 15% → écart à corriger » déclenche une action."}, {"type": "resource", "title": "Documentation openpyxl (gratuit)", "url": "https://openpyxl.readthedocs.io/", "provider": "Open Source", "desc": "La bibliothèque Python de référence pour lire/écrire Excel avec mise en forme, formules et graphiques."}]}'::jsonb FROM sms_courses WHERE code = 'MEAL-03';
INSERT INTO sms_lessons (course_id, title, type, points, order_index, content) SELECT id, 'Intégrer les cartes QGIS dans le rapport', 'notebook', 20, 5, '{"cells": [{"type": "md", "content": "## Le rapport qui a de la gueule\n\nUn rapport MEAL d''expert contient des **cartes**. On automatise leur génération avec PyQGIS (Projet 2) et on les insère dans le PDF final."}, {"type": "code", "lang": "python", "code": "# PyQGIS en mode ''headless'' : generer une carte sans ouvrir QGIS\n# (a lancer avec l''environnement QGIS)\nfrom qgis.core import QgsProject, QgsLayoutExporter\n\nproject = QgsProject.instance()\nproject.read(''/data/atlas_meal.qgz'')\nlayout = project.layoutManager().layoutByName(''Carte_MAG'')\n\nexporter = QgsLayoutExporter(layout)\nexporter.exportToPdf(''/out/carte_mag_T1.pdf'', QgsLayoutExporter.PdfExportSettings())\nprint(\"Carte exportee : carte_mag_T1.pdf\")\n", "output": "Carte exportee : carte_mag_T1.pdf"}, {"type": "callout", "variant": "tip", "title": "Le workflow complet", "content": "1) Python récupère les données par API → 2) génère un CSV → 3) PyQGIS charge ce CSV, applique la symbologie, exporte les cartes → 4) on assemble Excel + cartes dans un PDF. Tout en un script lançable d''un clic."}, {"type": "resource", "title": "ReportLab — générer des PDF en Python (gratuit)", "url": "https://www.reportlab.com/opensource/", "provider": "Open Source", "desc": "Pour assembler texte, tableaux et cartes dans un PDF professionnel automatiquement. La version open-source est gratuite."}]}'::jsonb FROM sms_courses WHERE code = 'MEAL-03';
INSERT INTO sms_lessons (course_id, title, type, points, order_index, content) SELECT id, 'Orchestrer et planifier le pipeline', 'notebook', 20, 6, '{"cells": [{"type": "md", "content": "## Le pipeline qui tourne tout seul\n\nUn vrai système automatisé s''exécute **sans vous**, à intervalle régulier. On assemble toutes les étapes dans un script unique, puis on le planifie (cron, GitHub Actions, ou un simple planificateur de tâches)."}, {"type": "embed", "title": "Notebook live : orchestrateur du pipeline complet", "code": "def pipeline_meal(trimestre):\n    print(f\"=== PIPELINE MEAL — {trimestre} ===\")\n    etapes = [\n      \"1. Connexion API KoboToolbox\",\n      \"2. Telechargement des nouvelles soumissions\",\n      \"3. Nettoyage (doublons, manquants, aberrants)\",\n      \"4. Calcul des indicateurs par district\",\n      \"5. Generation des cartes QGIS (Atlas)\",\n      \"6. Export Excel + assemblage PDF\",\n      \"7. Envoi email au coordinateur\",\n    ]\n    for e in etapes:\n        print(\"  [OK]\", e)\n    print(f\"=== Rapport {trimestre} genere automatiquement ===\")\n\npipeline_meal(\"T1-2025\")"}, {"type": "callout", "variant": "real", "title": "Ce que ça change", "content": "Une coordinatrice MEAL au Burkina Faso passait 2 semaines par trimestre à compiler les rapports. Avec un pipeline comme celui-ci, c''est devenu 1 clic. Elle consacre maintenant ce temps à l''accompagnement terrain. C''est ça, l''impact d''un super-expert MEAL."}, {"type": "resource", "title": "GitHub Actions — planifier gratuitement", "url": "https://docs.github.com/fr/actions", "provider": "GitHub (gratuit)", "desc": "Lancez votre pipeline automatiquement chaque semaine/mois dans le cloud, gratuitement pour les dépôts publics. Aucun serveur à gérer."}]}'::jsonb FROM sms_courses WHERE code = 'MEAL-03';
INSERT INTO sms_lessons (course_id, title, type, points, order_index, content) SELECT id, 'Redevabilité, éthique et qualité des données', 'notebook', 15, 7, '{"cells": [{"type": "md", "content": "## Un expert MEAL est aussi un gardien\n\nLa technique ne suffit pas. Un super-expert protège les bénéficiaires et garantit la fiabilité.\n\n### Les 4 piliers\n1. **Confidentialité** : anonymiser, chiffrer les données sensibles\n2. **Consentement** éclairé des enquêtés\n3. **Qualité** : contrôles de cohérence automatiques\n4. **Redevabilité** : mécanisme de retour pour les bénéficiaires"}, {"type": "embed", "title": "Notebook live : contrôle qualité automatique", "code": "import pandas as pd, numpy as np\nnp.random.seed(3)\ndf = pd.DataFrame({\n  ''age_months'': np.append(np.random.randint(6,60,48), [200, -3]),\n  ''muac_mm'': np.append(np.random.normal(130,15,48), [400, 30]),\n})\nalertes = []\nif (df.age_months > 59).any() or (df.age_months < 6).any():\n    alertes.append(\"Ages hors plage 6-59 mois detectes\")\nif (df.muac_mm > 300).any() or (df.muac_mm < 50).any():\n    alertes.append(\"MUAC aberrants detectes\")\nprint(\"CONTROLE QUALITE :\")\nfor a in alertes: print(\"  [ALERTE]\", a)\nprint(f\"\\n{len(df)} lignes verifiees, {len(alertes)} type(s) d''anomalie\")"}, {"type": "callout", "variant": "warning", "title": "Données = personnes réelles", "content": "Derrière chaque ligne, il y a un enfant, une famille. Protéger ces données n''est pas une option technique, c''est une responsabilité éthique. Un expert MEAL ne l''oublie jamais."}]}'::jsonb FROM sms_courses WHERE code = 'MEAL-03';
INSERT INTO sms_lessons (course_id, title, type, points, order_index, content) SELECT id, 'Capstone final — devenir Super-Expert MEAL', 'notebook', 25, 8, '{"cells": [{"type": "md", "content": "## Votre certification de Super-Expert MEAL\n\nVous avez parcouru tout le cycle :\n\n- **Projet 1** : concevoir et déployer la collecte (KoboCollect)\n- **Projet 2** : cartographier et analyser dans l''espace (QGIS)\n- **Projet 3** : automatiser le reporting de bout en bout\n\nCe capstone assemble tout en un système MEAL complet et autonome."}, {"type": "embed", "title": "Notebook live : le système MEAL intégré (synthèse finale)", "code": "print(\"SYSTEME MEAL INTEGRE — DataMEAL Academy\\n\" + \"=\"*45)\nchaine = {\n  \"COLLECTE  (Projet 1)\": \"Formulaire XLSForm + KoboCollect + API\",\n  \"ANALYSE   (Python)\"  : \"Nettoyage + indicateurs vs cadre logique\",\n  \"CARTO     (Projet 2)\": \"QGIS/PyQGIS + Atlas par district\",\n  \"REPORTING (Projet 3)\": \"Excel + cartes + PDF automatique\",\n  \"QUALITE   (Ethique)\" : \"Controles + anonymisation + redevabilite\",\n}\nfor etape, outil in chaine.items():\n    print(f\"  [MAITRISE] {etape:22} -> {outil}\")\nprint(\"\\n\" + \"=\"*45)\nprint(\"Vous etes desormais un(e) Super-Expert MEAL.\")\nprint(\"Demandez votre attestation finale !\")"}, {"type": "callout", "variant": "real", "title": "Le profil le plus recherché d''Afrique de l''Ouest", "content": "Très peu de professionnels maîtrisent la chaîne COMPLÈTE — de la conception du formulaire à l''automatisation du reporting cartographique. Vous en faites maintenant partie. C''est exactement ce que recherchent le FIDA, la Banque Mondiale, l''UNICEF et les grandes ONG."}, {"type": "md", "content": "### Pour aller plus loin (ressources gratuites)\n\nContinuez à pratiquer sur de vrais jeux de données humanitaires, contribuez à des projets open-source, et tenez votre portfolio à jour. La pratique fait le maître."}, {"type": "resource", "title": "Jeux de données humanitaires réels (gratuits)", "url": "https://data.humdata.org/", "provider": "HDX (OCHA)", "desc": "Des milliers de jeux de données réels d''Afrique de l''Ouest pour pratiquer : nutrition, WASH, sécurité alimentaire, déplacements de population."}]}'::jsonb FROM sms_courses WHERE code = 'MEAL-03';
